<?php
 namespace League\CommonMark\Inline\Parser; use League\CommonMark\Delimiter\Delimiter; use League\CommonMark\Inline\Element\Text; use League\CommonMark\InlineParserContext; final class BangParser implements InlineParserInterface { public function getCharacters(): array { return ['!']; } public function parse(InlineParserContext $inlineContext): bool { $cursor = $inlineContext->getCursor(); if ($cursor->peek() === '[') { $cursor->advanceBy(2); $node = new Text('![', ['delim' => true]); $inlineContext->getContainer()->appendChild($node); $delimiter = new Delimiter('!', 1, $node, true, false, $cursor->getPosition()); $inlineContext->getDelimiterStack()->push($delimiter); return true; } return false; } } 